import{U as e,gt as t,nt as n,rt as r}from"./chunks/framework.B3obAz7o.js";var i=JSON.parse(`{"title":"Features","description":"","frontmatter":{},"headers":[],"relativePath":"guide/features.md","filePath":"guide/features.md","lastUpdated":1784604664000}`),a={name:`guide/features.md`};function o(e,i,a,o,s,c){return t(),n(`div`,null,[...i[0]||=[r(`<h1 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to “Features”">​</a></h1><p>fontmin-rs is currently in beta. This page records the implemented public surface and the boundaries that matter when choosing an entry point. For a first project, continue with <a href="./getting-started">Get Started</a>.</p><h2 id="entry-points" tabindex="-1">Entry Points <a class="header-anchor" href="#entry-points" aria-label="Permalink to “Entry Points”">​</a></h2><table tabindex="0"><thead><tr><th>Entry point</th><th>Best for</th><th>Runtime model</th></tr></thead><tbody><tr><td><code>fontmin-rs</code> CLI</td><td>Shell scripts, CI, and one-off processing</td><td>Native Rust executable</td></tr><tr><td><code>fontmin-rs</code> Node API</td><td>Build integrations and custom pipelines</td><td>Native binding, forced WASM, or native-first auto</td></tr><tr><td><code>@fontmin-rs/wasm</code></td><td>Browser and worker applications</td><td>Asynchronous, in-memory WASM</td></tr></tbody></table><p>The npm package also exposes the CLI command, typed configuration helpers, built-in plugin declarations, presets, and a Fontmin-compatible chain.</p><h2 id="font-processing" tabindex="-1">Font Processing <a class="header-anchor" href="#font-processing" aria-label="Permalink to “Font Processing”">​</a></h2><table tabindex="0"><thead><tr><th>Capability</th><th>Supported operations</th></tr></thead><tbody><tr><td>Subsetting</td><td>Keep glyphs by text, text file, code points, basic text, or Unicode range groups.</td></tr><tr><td>Web font conversion</td><td>TTF to and from WOFF or WOFF2, including WOFF metadata and private data blocks.</td></tr><tr><td>Legacy conversion</td><td>TTF to and from EOT, plus TTF to SVG font and SVG font to TTF.</td></tr><tr><td>OpenType conversion</td><td>Convert static CFF OTF or instantiate CFF2 variable OTF as a static TrueType <code>glyf</code> font.</td></tr><tr><td>Icon fonts</td><td>Combine multiple SVG icons into TTF and generate optional glyph class CSS.</td></tr><tr><td>CSS generation</td><td>Generate <code>@font-face</code> CSS, SCSS, or Less with local sources, Base64 data, and <code>unicode-range</code> values.</td></tr><tr><td>Inspection</td><td>Detect and inspect TTF, OTF, WOFF, WOFF2, and EOT metadata.</td></tr><tr><td>Character coverage</td><td>Report requested, supported, and missing Unicode values before subsetting; optionally fail strictly.</td></tr></tbody></table><p>The low-level Node and browser APIs expose these operations directly. The file-based pipelines compose the same operations through built-in plugins. See the <a href="./../api/node">Node API</a> and <a href="./../api/wasm">Browser WASM API</a> for the complete callable surface.</p><h2 id="pipelines-and-presets" tabindex="-1">Pipelines and Presets <a class="header-anchor" href="#pipelines-and-presets" aria-label="Permalink to “Pipelines and Presets”">​</a></h2><ul><li><code>optimize(config)</code> discovers file inputs, applies plugins, reuses matching cache entries, and writes outputs in Node.js.</li><li><code>optimizeBrowser(config)</code> applies built-in and custom browser plugins to named in-memory assets without filesystem access.</li><li><code>modernWeb(options)</code> normalizes supported OTF input, subsets it, and emits WOFF, WOFF2, and CSS.</li><li><code>fontminCompatPreset(options)</code> follows the classic Fontmin output order for EOT, SVG, WOFF, WOFF2, and CSS.</li><li>The CLI <code>iconfont</code> preset groups SVG icon inputs into <code>iconfont.ttf</code> and <code>iconfont.css</code>.</li><li><code>deliverySlices()</code> and CLI delivery slices create named subsets with matching CSS <code>unicode-range</code> descriptors.</li></ul><p>Built-in plugin factories are <code>glyph</code>, <code>deliverySlices</code>, <code>otf2ttf</code>, <code>ttf2woff</code>, <code>ttf2woff2</code>, <code>ttf2eot</code>, <code>ttf2svg</code>, <code>svg2ttf</code>, <code>svgs2ttf</code>, and <code>css</code>.</p><p>Node <code>optimize(config)</code> selects one built-in runtime for the whole pipeline: <code>native</code>, <code>wasm</code>, or native-first <code>auto</code>. Cache entries are separated by the selected runtime. Filesystem work and custom JavaScript hooks always remain in Node.js.</p><h2 id="cli-and-configuration" tabindex="-1">CLI and Configuration <a class="header-anchor" href="#cli-and-configuration" aria-label="Permalink to “CLI and Configuration”">​</a></h2><p>The CLI provides <code>init</code>, <code>coverage</code>, <code>subset</code>, <code>convert</code>, <code>build</code>, <code>bench</code>, <code>inspect</code>, and <code>doctor</code> commands. It can load JSON, JSONC, TS, MTS, MJS, and CJS configuration files; executable module configs require Node.js 22 or newer.</p><p>Use <a href="./cli">Command Line</a> for command flags and examples. Use <a href="./config">Configuration</a> for file discovery, output control, caching, subsetting modes, OTF variation coordinates, and the boundary between Rust built-ins and custom Node.js plugins.</p><h2 id="compatibility-and-limits" tabindex="-1">Compatibility and Limits <a class="header-anchor" href="#compatibility-and-limits" aria-label="Permalink to “Compatibility and Limits”">​</a></h2><ul><li>EOT exists for older Internet Explorer compatibility; modern projects should normally prefer WOFF2 with WOFF as a fallback.</li><li>CFF/CFF2 conversion always produces a static TTF. It removes variation tables, and Type 2 hinting is not preserved.</li><li><code>modernWeb()</code> intentionally emits WOFF, WOFF2, and CSS only. Add legacy plugins explicitly or use <code>fontminCompatPreset()</code> when required.</li><li>The browser package has no path inputs, glob expansion, CLI, disk cache, output directory, or filesystem hooks.</li><li>Custom Node.js plugins may use filesystem and diagnostic context helpers. Browser plugins use a smaller, memory-only hook surface.</li></ul><p>Existing Fontmin users should read <a href="./migration">Migration From Fontmin</a>. Internal package and runtime boundaries are documented in <a href="./../architecture">Architecture</a>.</p><h2 id="project-status" tabindex="-1">Project Status <a class="header-anchor" href="#project-status" aria-label="Permalink to “Project Status”">​</a></h2><p>Current development is focused on release hardening, richer diagnostics, performance, and broader Fontmin compatibility. The longer-term direction is tracked in the <a href="./../fontmin-rs-design">design document</a>; maintainers can use the <a href="./../releasing">release preparation checklist</a> for the candidate gate.</p>`,20)]])}var s=e(a,[[`render`,o]]);export{i as __pageData,s as default};